def test_rate_limit():
    for i in range(100):
        r = client.get('/api/data')
    assert r.status_code == 429

def test_cors_headers():
    r = client.options('/api/data', headers={'Origin': 'http://localhost'})
    assert 'Access-Control-Allow-Origin' in r.headers

def test_oauth_scope():
    r = client.get('/api/admin', headers={'Authorization': f'Bearer {user_token}'})
    assert r.status_code == 403

def test_content_negotiation():
    r = client.get('/api/report', headers={'Accept': 'application/xml'})
    assert 'xml' in r.headers['Content-Type']

def test_api_key_auth():
    r = client.get('/api/data', headers={'X-API-Key': 'invalid'})
    assert r.status_code == 401
